// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.io.File;

import org.eclipse.rdf4j.common.transaction.IsolationLevels;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.TupleQuery;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.query.explanation.Explanation;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.eclipse.rdf4j.repository.sail.SailRepositoryConnection;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbOperatorFeedbackPlanningTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI MEMBER_OF = VF.createIRI("urn:test:operator-feedback:memberOf");
	private static final IRI DEPARTMENT = VF.createIRI("urn:test:operator-feedback:department");
	private static final IRI MAKES_OFFER = VF.createIRI("urn:test:operator-feedback:makesOffer");
	private static final IRI PAGE = VF.createIRI("urn:test:operator-feedback:page");
	private static final IRI REVIEW = VF.createIRI("urn:test:operator-feedback:review");
	private static final IRI AWARD = VF.createIRI("urn:test:operator-feedback:award");
	private static final IRI POSITION = VF.createIRI("urn:test:operator-feedback:position");
	private static final int ORG_COUNT = 3;
	private static final int PERSONS_PER_ORG = 24;
	private static final int DEPARTMENTS_PER_ORG = 2;
	private static final int OFFERS_PER_DEPARTMENT = 3;
	private static final int REVIEWS_PER_PAGE = 35;
	private static final int EXPECTED_LEFT_JOIN_ROWS = ORG_COUNT
			* PERSONS_PER_ORG
			* DEPARTMENTS_PER_ORG
			* OFFERS_PER_DEPARTMENT
			* REVIEWS_PER_PAGE;
	private static final int EXPECTED_OPTIONAL_UNION_ROWS = EXPECTED_LEFT_JOIN_ROWS
			+ ORG_COUNT * DEPARTMENTS_PER_ORG * OFFERS_PER_DEPARTMENT;

	@Test
	void secondPlanUsesLeftJoinOperatorFeedbackForBoundOptionalFanout(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSparseOptionalFanout(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				assertEquals(EXPECTED_LEFT_JOIN_ROWS, count(connection, leftJoinFanoutQuery()));
				connection.prepareTupleQuery(leftJoinFanoutQuery()).explain(Explanation.Level.Telemetry);

				String trainedPlan = connection.prepareTupleQuery(leftJoinFanoutQuery())
						.explain(Explanation.Level.Optimized)
						.toString();

				assertTrue(trainedPlan.contains("plannedEstimateSource=learned_operator")
						|| trainedPlan.contains("plannedEstimateSource=learned_left_join_surface"),
						"Second plan should apply completed-query operator feedback to the bound OPTIONAL fanout:\n"
								+ trainedPlan);
			}
		} finally {
			repository.shutDown();
		}
	}

	@Test
	void secondPlanUsesUnionOperatorFeedbackForOptionalUnionFanout(@TempDir File dataDir) throws Exception {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,ospc,psoc,posc");
		LmdbStore store = new LmdbStore(dataDir, config);
		SailRepository repository = new SailRepository(store);
		repository.init();

		try {
			loadSparseOptionalFanout(repository);
			store.getBackingStore().getSketchBasedJoinEstimator().rebuild();
			LmdbPlannerAwait.awaitSketchesReady(store);

			try (SailRepositoryConnection connection = repository.getConnection()) {
				assertEquals(EXPECTED_OPTIONAL_UNION_ROWS, count(connection, optionalUnionFanoutQuery()));
				connection.prepareTupleQuery(optionalUnionFanoutQuery()).explain(Explanation.Level.Telemetry);

				String trainedPlan = connection.prepareTupleQuery(optionalUnionFanoutQuery())
						.explain(Explanation.Level.Optimized)
						.toString();

				assertTrue(trainedPlan.contains("Union")
						&& trainedPlan.contains("plannedEstimateSource=learned_operator"),
						"Second plan should apply completed-query operator feedback to the OPTIONAL UNION fanout:\n"
								+ trainedPlan);
			}
		} finally {
			repository.shutDown();
		}
	}

	private static long count(SailRepositoryConnection connection, String query) {
		TupleQuery tupleQuery = connection.prepareTupleQuery(query);
		try (TupleQueryResult result = tupleQuery.evaluate()) {
			assertTrue(result.hasNext(), "Expected count result");
			return ((Literal) result.next().getValue("count")).longValue();
		}
	}

	private static String leftJoinFanoutQuery() {
		return String.join("\n",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  ?person <urn:test:operator-feedback:memberOf> ?org .",
				"  ?org <urn:test:operator-feedback:department> ?department .",
				"  ?department <urn:test:operator-feedback:makesOffer> ?offer .",
				"  ?offer <urn:test:operator-feedback:page> ?page .",
				"  OPTIONAL {",
				"    ?page <urn:test:operator-feedback:review> ?review .",
				"  }",
				"}");
	}

	private static String optionalUnionFanoutQuery() {
		return String.join("\n",
				"SELECT (COUNT(*) AS ?count) WHERE {",
				"  ?person <urn:test:operator-feedback:memberOf> ?org .",
				"  ?org <urn:test:operator-feedback:department> ?department .",
				"  ?department <urn:test:operator-feedback:makesOffer> ?offer .",
				"  ?offer <urn:test:operator-feedback:page> ?page .",
				"  OPTIONAL {",
				"    { ?page <urn:test:operator-feedback:review> ?opt . }",
				"    UNION",
				"    { ?person <urn:test:operator-feedback:award> ?opt . }",
				"  }",
				"}");
	}

	private static void loadSparseOptionalFanout(SailRepository repository) {
		try (SailRepositoryConnection connection = repository.getConnection()) {
			connection.begin(IsolationLevels.NONE);
			for (int orgIndex = 0; orgIndex < ORG_COUNT; orgIndex++) {
				Resource org = VF.createIRI("urn:test:operator-feedback:org:" + orgIndex);
				for (int personIndex = 0; personIndex < PERSONS_PER_ORG; personIndex++) {
					Resource person = VF.createIRI("urn:test:operator-feedback:person:" + orgIndex + ":"
							+ personIndex);
					connection.add(person, MEMBER_OF, org);
					connection.add(person, POSITION, VF.createLiteral((personIndex % 5) + 1));
					if (personIndex == 0) {
						connection.add(person, AWARD, VF.createIRI("urn:test:operator-feedback:award:" + orgIndex));
					}
				}
				for (int departmentIndex = 0; departmentIndex < DEPARTMENTS_PER_ORG; departmentIndex++) {
					Resource department = VF.createIRI("urn:test:operator-feedback:department:" + orgIndex + ":"
							+ departmentIndex);
					connection.add(org, DEPARTMENT, department);
					for (int offerIndex = 0; offerIndex < OFFERS_PER_DEPARTMENT; offerIndex++) {
						Resource offer = VF.createIRI("urn:test:operator-feedback:offer:" + orgIndex + ":"
								+ departmentIndex + ":" + offerIndex);
						Resource page = VF.createIRI("urn:test:operator-feedback:page:" + orgIndex + ":"
								+ departmentIndex + ":" + offerIndex);
						connection.add(department, MAKES_OFFER, offer);
						connection.add(offer, PAGE, page);
						for (int reviewIndex = 0; reviewIndex < REVIEWS_PER_PAGE; reviewIndex++) {
							connection.add(page, REVIEW, VF.createIRI("urn:test:operator-feedback:review:" + orgIndex
									+ ":" + departmentIndex + ":" + offerIndex + ":" + reviewIndex));
						}
					}
				}
			}
			connection.commit();
		}
	}
}
